      p.part_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.model_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.manufacturer LIKE CONCAT('%', #{keyword}, '%')
      OR p.part_code LIKE CONCAT('%', #{keyword}, '%')
      OR c.category_name LIKE CONCAT('%', #{keyword}, '%')
  )

mapper.select:
