FROM tb_part_category
WHERE company_id = #{companyId}
  AND category_id = #{categoryId}

SELECT EXISTS (
    SELECT 1
    FROM tb_pc_part
    WHERE company_id = #{companyId}
      AND part_code = #{partCode}

        AND part_id <> #{excludePartId}

